// Suporta webhook typeVersion 1 (body direto) e typeVersion 2 (body aninhado)
const raw = $input.first().json;
const payload = (raw.body && typeof raw.body === 'object' && raw.body !== null) ? raw.body : raw;

// Ignora eventos que nao sao mensagens recebidas (connection.update, read receipts, etc)
const event = payload.event || '';
if (event !== '' && event !== 'messages.upsert') return [];

const data = payload.data || {};
const key = data.key || {};
const msg = data.message || {};

const text =
  msg.conversation ||
  (msg.extendedTextMessage && msg.extendedTextMessage.text) ||
  (msg.imageMessage && msg.imageMessage.caption) ||
  (msg.videoMessage && msg.videoMessage.caption) ||
  (msg.documentMessage && msg.documentMessage.caption) ||
  '';

const remoteJid = key.remoteJid || '';
const fromMe = key.fromMe === true;
const instance = payload.instance || 'Teste';

if (fromMe) return [];
if (!text.trim()) return [];
if (remoteJid.includes('@g.us')) return [];

const phone = remoteJid
  .replace('@s.whatsapp.net', '')
  .replace('@c.us', '');

return [{ json: { text: text.trim(), phone: phone, remoteJid: remoteJid, instance: instance } }];

const input = $input.first().json;
const text = (input.text || '').toLowerCase();
const now = new Date();
const fmt = d => d.toISOString().split('T')[0];
const addDays = (n) => { const d = new Date(now); d.setDate(d.getDate() + n); return fmt(d); };
const dow = now.getDay();
const daysToMon = dow === 0 ? 6 : dow - 1;
const monday = new Date(now);
monday.setDate(now.getDate() - daysToMon);

// clientMap como array para evitar chave duplicada e suportar multiplos aliases
const clientMap = [
  { keys: ['antonio neto', 'antonio'], id: 'act_497795903676192', nome: 'Antonio Neto' },
  { keys: ['gabriel jacinto', 'gabriel'], id: 'act_2493856707309984', nome: 'Gabriel Jacinto' },
  { keys: ['dani escudero', 'dani'], id: 'act_2145598605527232', nome: 'Dani Escudero' },
  { keys: ['agro'], id: 'act_929521557422139', nome: 'Agro' },
  { keys: ['escola de musica', 'escola de m\u00fasica', 'escola'], id: 'act_544347952854095', nome: 'Escola de M\u00fasica' },
  { keys: ['panmalhas'], id: 'act_1509005182799187', nome: 'Panmalhas Assessoria T\u00eaxtil' },
  { keys: ['gfix store', 'gfix'], id: 'act_2811791829124905', nome: 'GFiX Store' },
  { keys: ['arte em gelo', 'arte em'], id: 'act_5585082641598366', nome: 'Arte em Gelo' },
  { keys: ['itag tecnologia', 'itag'], id: 'act_738466861151636', nome: 'ITAG Tecnologia' },
  { keys: ['hi dogz', 'dogz'], id: 'act_873195821346004', nome: 'Hi Dogz' },
  { keys: ['batata bistro', 'batata bistr\u00f4', 'batata'], id: 'act_1673012226810411', nome: 'Batata Bistr\u00f4' },
  { keys: ['caribbean bronze', 'caribbean'], id: 'act_1082397873705862', nome: 'Caribbean Bronze' },
  { keys: ['larissa kelleter', 'larissa'], id: 'act_738280412237298', nome: 'Larissa Kelleter' }
];

// Ordena por comprimento da primeira chave (mais especifico primeiro)
clientMap.sort((a, b) => b.keys[0].length - a.keys[0].length);

// Detecta pedido de relatorio
const isRelatorio = text.includes('relat');

let clientFound = null;
for (let i = 0; i < clientMap.length; i++) {
  const entry = clientMap[i];
  for (let j = 0; j < entry.keys.length; j++) {
    if (text.includes(entry.keys[j])) {
      clientFound = entry;
      break;
    }
  }
  if (clientFound) break;
}

const today = fmt(now);
const yesterday = addDays(-1);
// Corrigido: ultimos 7 dias = D-7 ate D-1 (igual ao Meta Ads)
const last7End = addDays(-1);
const last7Start = addDays(-7);

const isRelatorioWithClient = (isRelatorio && clientFound !== null) ? 'true' : 'false';
// Modo todos: pede relatorio sem especificar cliente
const isRelatorioTodos = (isRelatorio && clientFound === null) ? 'true' : 'false';

// Detecta periodo solicitado e mapeia para date_preset do Meta Ads
const hasMesPassado = text.includes('m\u00eas passado') || text.includes('mes passado');
const hasEsseMes = text.includes('esse m\u00eas') || text.includes('este m\u00eas') || text.includes('esse mes') || text.includes('este mes');

let datePreset = 'last_7d';
let periodoLabel = '\u00faltimos 7 dias';
let periodStart = last7Start;
let periodEnd = last7End;

if (hasMesPassado) {
  datePreset = 'last_month';
  periodoLabel = 'm\u00eas passado';
  const firstOfMonth = new Date(now.getFullYear(), now.getMonth(), 1);
  const lastOfPrevMonth = new Date(firstOfMonth.getTime() - 86400000);
  const firstOfPrevMonth = new Date(lastOfPrevMonth.getFullYear(), lastOfPrevMonth.getMonth(), 1);
  periodStart = fmt(firstOfPrevMonth);
  periodEnd = fmt(lastOfPrevMonth);
} else if (text.includes('ontem')) {
  datePreset = 'yesterday';
  periodoLabel = 'ontem';
  periodStart = yesterday;
  periodEnd = yesterday;
} else if (text.includes('hoje')) {
  datePreset = 'today';
  periodoLabel = 'hoje';
  periodStart = today;
  periodEnd = today;
} else if (text.includes('essa semana') || text.includes('esta semana') || text.includes('da semana')) {
  datePreset = 'this_week_mon_today';
  periodoLabel = 'essa semana';
  periodStart = fmt(monday);
  periodEnd = today;
} else if (text.includes('14 dias')) {
  datePreset = 'last_14d';
  periodoLabel = '\u00faltimos 14 dias';
  periodStart = addDays(-14);
  periodEnd = addDays(-1);
} else if (text.includes('30 dias') || hasEsseMes) {
  datePreset = 'last_30d';
  periodoLabel = '\u00faltimos 30 dias';
  periodStart = addDays(-30);
  periodEnd = addDays(-1);
}

return [{
  json: {
    text: input.text,
    phone: input.phone,
    remoteJid: input.remoteJid,
    instance: input.instance,
    today: today,
    yesterday: yesterday,
    weekStart: fmt(monday),
    last7: last7Start,
    last30: addDays(-30),
    last7Start: last7Start,
    last7End: last7End,
    metaToken: 'EAAeVLzZANk8oBQ79Ue5UimCCCYL9uNZCH9EZA7vZAJtqB5B9aQ6mO53EnUI1b8Cskpq9tRsYZAaDKvZB1kLZABjbqgwi3aenhyPnAtQkeineasNmaZA7vue9ndlaErc59UFZBaMBeDnBC8ZBpXtn9PdUP4OMQvkd53QZAL1jI9SC49WGZCvgopdZABkhGKCEuVStyYGRfYPrlhksx7HHkqZBNWo5gMLhREik5hvkp1JA7X',
    isRelatorio: isRelatorio,
    isRelatorioWithClient: isRelatorioWithClient,
    isRelatorioTodos: isRelatorioTodos,
    clientFound: clientFound ? clientFound.id : null,
    clientNome: clientFound ? clientFound.nome : null,
    datePreset: datePreset,
    periodoLabel: periodoLabel,
    periodStart: periodStart,
    periodEnd: periodEnd
  }
}];

const https = require('https');
const httpGet = (url) => new Promise((resolve, reject) => {
  https.get(url, (res) => {
    let d = '';
    res.on('data', c => d += c);
    res.on('end', () => { try { resolve(JSON.parse(d)); } catch(e) { reject(e); } });
  }).on('error', reject);
});

const ctx = $('Calcular Datas').first().json;
const token = ctx.metaToken;
const datePreset = ctx.datePreset || 'last_7d';
const periodStart = ctx.periodStart;
const periodEnd = ctx.periodEnd;
const periodoLabel = ctx.periodoLabel || 'últimos 7 dias';
const phone = ctx.phone;

// 9 clientes ativos para relatório automático
const clientMap = [
  { id: 'act_929521557422139',   nome: 'Agro',                      type: 'lead'     },
  { id: 'act_5585082641598366',  nome: 'Arte em Gelo',              type: 'lead'     },
  { id: 'act_1673012226810411',  nome: 'Batata Bistrô',             type: 'purchase' },
  { id: 'act_1082397873705862',  nome: 'Caribbean Bronze',          type: 'lead'     },
  { id: 'act_544347952854095',   nome: 'Escola de Música',          type: 'lead'     },
  { id: 'act_2811791829124905',  nome: 'GFiX Store',                type: 'lead'     },
  { id: 'act_873195821346004',   nome: 'Hi Dogz',                   type: 'purchase' },
  { id: 'act_738466861151636',   nome: 'ITAG Tecnologia',           type: 'lead'     },
  { id: 'act_1509005182799187',  nome: 'Panmalhas Assessoria Têxtil', type: 'lead'   }
];

const fmtMoney = (val) => {
  const n = parseFloat(val) || 0;
  const fixed = n.toFixed(2);
  const parts = fixed.split('.');
  parts[0] = parts[0].replace(/(\d)(?=(\d{3})+$)/g, '$1.');
  return parts[0] + ',' + parts[1];
};

const fmtNum = (val) => {
  const n = parseInt(val) || 0;
  return String(n).replace(/(\d)(?=(\d{3})+$)/g, '$1.');
};

const fmtBR = (dateStr) => {
  if (!dateStr) return '??/??';
  const d = new Date(dateStr + 'T12:00:00Z');
  return String(d.getUTCDate()).padStart(2, '0') + '/' + String(d.getUTCMonth() + 1).padStart(2, '0');
};

const LEAD_ACTION = 'onsite_conversion.total_messaging_connection';
const fields = 'spend,impressions,clicks,actions,action_values';

const dateRange = periodStart === periodEnd
  ? '_📅 ' + fmtBR(periodStart) + ' (' + periodoLabel + ')_'
  : '_📅 ' + fmtBR(periodStart) + ' a ' + fmtBR(periodEnd) + ' (' + periodoLabel + ')_';

const fetchClient = async (client) => {
  try {
    const url = 'https://graph.facebook.com/v19.0/' + client.id + '/insights?date_preset=' +
      encodeURIComponent(datePreset) + '&fields=' + encodeURIComponent(fields) +
      '&level=campaign&access_token=' + token;
    const data = await httpGet(url);

    if (data.error) return null; // ignora conta com erro de acesso

    const campaigns = data.data || [];
    if (!campaigns.length) return null; // sem dados no período

    let totalSpend = 0, totalImpressions = 0, totalClicks = 0;
    for (const c of campaigns) {
      totalSpend += parseFloat(c.spend || '0');
      totalImpressions += parseInt(c.impressions || '0');
      totalClicks += parseInt(c.clicks || '0');
    }

    if (totalSpend === 0) return null; // sem investimento no período, ignora

    let reportText;

    if (client.type === 'purchase') {
      let totalPurchases = 0, totalRevenue = 0;
      for (const c of campaigns) {
        const pa = (c.actions || []).find(a =>
          a.action_type === 'purchase' || a.action_type === 'offsite_conversion.fb_pixel_purchase');
        if (pa) totalPurchases += parseInt(pa.value);
        const ra = (c.action_values || []).find(a =>
          a.action_type === 'purchase' || a.action_type === 'offsite_conversion.fb_pixel_purchase');
        if (ra) totalRevenue += parseFloat(ra.value);
      }
      const cpp = totalPurchases > 0 ? totalSpend / totalPurchases : 0;
      reportText =
        '*' + client.nome.toUpperCase() + '*\n\n' +
        dateRange + '\n\n' +
        '*Meta Ads*\n\n' +
        'Impressões: ' + fmtNum(totalImpressions) + '\n\n' +
        'Cliques: ' + fmtNum(totalClicks) + '\n\n' +
        'Vendas: ' + totalPurchases + '\n\n' +
        'Faturamento: R$ ' + fmtMoney(totalRevenue) + '\n\n' +
        'Custo por venda: R$ ' + fmtMoney(cpp) + '\n\n' +
        '*INVESTIMENTO TOTAL: R$ ' + fmtMoney(totalSpend) + '*';
    } else {
      let leadSpend = 0, totalLeads = 0;
      for (const c of campaigns) {
        const la = (c.actions || []).find(a => a.action_type === LEAD_ACTION);
        if (la) {
          leadSpend += parseFloat(c.spend || '0');
          totalLeads += parseInt(la.value);
        }
      }
      const cpl = totalLeads > 0 ? leadSpend / totalLeads : 0;
      reportText =
        '*' + client.nome.toUpperCase() + '*\n\n' +
        dateRange + '\n\n' +
        '*Meta Ads*\n\n' +
        'Impressões: ' + fmtNum(totalImpressions) + '\n\n' +
        'Cliques: ' + fmtNum(totalClicks) + '\n\n' +
        'Leads: ' + totalLeads + '\n\n' +
        'Custo por lead: R$ ' + fmtMoney(cpl) + '\n\n' +
        '*INVESTIMENTO TOTAL: R$ ' + fmtMoney(totalSpend) + '*';
    }

    return { json: { phone: phone, output: reportText } };
  } catch(e) {
    return null; // ignora clientes com erro de conexão
  }
};

const allResults = await Promise.all(clientMap.map(fetchClient));
const results = allResults.filter(r => r !== null);

if (results.length === 0) {
  return [{ json: { phone: phone, output: '❌ Nenhum dado encontrado para o período (' + periodoLabel + ').' } }];
}

return results;

const metaData = $input.first().json;
