};

if (!campaigns.length) {
  return [{ json: {
    phone: ctx.phone,
    output: '\u274c Sem dados para *' + (ctx.clientNome || '').toUpperCase() + '* no per\u00edodo solicitado.'
  } }];
}

const purchaseAccountIds = ['act_873195821346004', 'act_1673012226810411'];
const isPurchase = purchaseAccountIds.includes(ctx.clientFound);

let totalSpend = 0;
let totalImpressions = 0;
let totalClicks = 0;

for (const c of campaigns) {
  totalSpend += parseFloat(c.spend || '0');
  totalImpressions += parseInt(c.impressions || '0');
  totalClicks += parseInt(c.clicks || '0');
}

const clientNameUpper = (ctx.clientNome || '').toUpperCase();
