  : '_\ud83d\udcc5 ' + fmtBR(periodStart) + ' a ' + fmtBR(periodEnd) + ' (' + periodoLabel + ')_';

let reportText;

if (isPurchase) {
  let totalPurchases = 0;
  let totalRevenue = 0;
