const baseId = campaignId || accountId;
try {
  const url = `https://graph.facebook.com/v19.0/${baseId}/adsets?fields=id,name,status,daily_budget,lifetime_budget,campaign_id&limit=100&access_token=${token}`;
  const data = await httpGet(url);
  if (data.error) return `Erro Meta API: ${data.error.message}`;
  if (!data.data || data.data.length === 0) return 'Nenhum conjunto de anúncios encontrado';
  const adsets = data.data.map(a => ({
    id: a.id,
    nome: a.name,
    status: a.status,
    budget_diario_reais: a.daily_budget ? (parseInt(a.daily_budget) / 100).toFixed(2) : null,
    budget_total_reais: a.lifetime_budget ? (parseInt(a.lifetime_budget) / 100).toFixed(2) : null
  }));
  return JSON.stringify(adsets);
} catch(e) { return `Erro de conexão: ${e.message}`; }

